const AVAILABLE_LIBRARIES = Object.keys(LIBRARIES).join(", ")

export function getShapeLibrary(name: string): string {
    const sanitized = name.toLowerCase().replace(/[^a-z0-9_-]/g, "")
    if (sanitized !== name.toLowerCase()) {
        return `Invalid library name "${name}". Use only letters, numbers, underscores, and hyphens.`
    }
    const content = LIBRARIES[sanitized]
    if (!content) {
        return `Library "${name}" not found. Available: ${AVAILABLE_LIBRARIES}`
    }
    return content
}
